  "plan_text": "{\n  \"generated_at\": \"2026-06-29T22:34:40.372848+00:00\",\n  \"plan_text\": \"{\\n  \\\"generated_at\\\": \\\"2026-06-29T22:26:55.599733+00:00\\\",\\n  \\\"plan_text\\\": \\\"```json\\\\n{\\\\n  \\\\\\\"themes\\\\\\\": [\\\\n    \\\\\\\"Japan-China business bridge as primary narrative: Japanese SMEs (飲食店、制造、零售、小売) needing inbound / 多言語 / 华人渠道 partner with Chinese-marketing or 大中華-side founders and operators.\\\\\\\",\\\\n    \\\\\\\"Orbit's differentiated value is relationship reasoning, not contact storage — every mock record must answer: who is this person, what do they want, what can they offer, why should they meet, what happens next.\\\\\\\",\\\\n    \\\\\\\"Event-scoped intent dominates profile-only intent — the same user appears differently across an inbound 活動, an investor mixer, and a 中華圏 founder dinner.\\\\\\\",\\\\n    \\\\\\\"Three-layer data model: product layer (users/events/contacts/connections), AI semantic layer (ai_analyses, recommendations, relationship_profiles), test/demo layer (golden_matches, dirty_cases, demo_scenarios).\\\\\\\",\\\\n    \\\\\\\"Field-confirmed facts are separated from AI-inferred traits; confidence and source_refs travel with every inference so the demo never looks like hallucinated chatbot output.\\\\\\\",\\\\n    \\\\\\\"Bilingual reality (ja/zh/en) — Japanese-first for 日本 local SMEs, Chinese-first for 华人 operators, mixed for cross-border orchestrators; never make one language decorative.\\\\\\\",\\\\n    \\\\\\\"Deterministic expander produces all v1 volumes from a seeded blueprint so a second run reproduces the same fixtures and recommendation regressions are testable.\\\\\\\"\\\\n  ],\\\\n  \\\\\\\"persona_templates\\\\\\\": [\\\\n    {\\\\n      \\\\\\\"id\\\\\\\": \\\\\\\"jp_sme_owner\\\\\\\",\\\\n      \\\\\\\"label\\\\\\\": \\\\\\\"日本ローカル中小企業オーナー\\\\\\\",\\\\n      \\\\\\\"weight_pct\\\\\\\": \\\\\\\"35-45\\\\\\\",\\\\n      \\\\\\\"language\\\\\\\": [\\\\\\\"ja\\\\\\\"],\\\\n      \\\\\\\"industry_seeds\\\\\\\": [\\\\\\\"restaurant\\\\\\\", \\\\\\\"retail\\\\\\\", \\\\\\\"manufacturing\\\\\\\", \\\\\\\"logistics\\\\\\\"],\\\\n      \\\\\\\"looking_for\\\\\\\": [\\\\\\\"インバウンド集客\\\\\\\", \\\\\\\"中国語対応パートナー\\\\\\\", \\\\\\\"業務効率化\\\\\\\", \\\\\\\"DXPoC\\\\\\\"],\\\\n      \\\\\\\"can_offer\\\\\\\": [\\\\\\\"実店舗での実証実験\\\\\\\", \\\\\\\"現場導入先\\\\\\\", \\\\\\\"日本人顧客ネットワーク\\\\\\\"],\\\\n      \\\\\\\"tone\\\\\\\": \\\\\\\"丁寧、慎重、対面信頼重視\\\\\\\",\\\\n      \\\\\\\"follow_up_channel\\\\\\\": \\\\\\\"email_then_inperson\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"id\\\\\\\": \\\\\\\"cn_operator_in_jp\\\\\\\",\\\\n      \\\\\\\"label\\\\\\\": \\\\\\\"在日华人事業者 / ブリッジ役\\\\\\\",\\\\n      \\\\\\\"weight_pct\\\\\\\": \\\\\\\"20-28\\\\\\\",\\\\n      \\\\\\\"language\\\\\\\": [\\\\\\\"zh\\\\\\\", \\\\\\\"ja\\\\\\\"],\\\\n      \\\\\\\"industry_seeds\\\\\\\": [\\\\\\\"marketing\\\\\\\", \\\\\\\"cross_border_ecom\\\\\\\", \\\\\\\"media\\\\\\\", \\\\\\\"consulting\\\\\\\"],\\\\n      \\\\\\\"looking_for\\\\\\\": [\\\\\\\"日本クライアント\\\\\\\", \\\\\\\"現地パイロット店舗\\\\\\\", \\\\\\\"共同コンテンツ枠\\\\\\\"],\\\\n      \\\\\\\"can_offer\\\\\\\": [\\\\\\\"華語圏コンテンツ制作\\\\\\\", \\\\\\\"中国語SNS運用\\\\\\\", \\\\\\\"コミュニティ動員\\\\\\\"],\\\\n      \\\\\\\"tone\\\\\\\": \\\\\\\"実務寄り、提案具体的\\\\\\\",\\\\n      \\\\\\\"follow_up_channel\\\\\\\": \\\\\\\"wechat_or_line\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"id\\\\\\\": \\\\\\\"cn_founder_remote\\\\\\\",\\\\n      \\\\\\\"label\\\\\\\": \\\\\\\"大中華区側founder / operator\\\\\\\",\\\\n      \\\\\\\"weight_pct\\\\\\\": \\\\\\\"10-15\\\\\\\",\\\\n      \\\\\\\"language\\\\\\\": [\\\\\\\"zh\\\\\\\", \\\\\\\"en\\\\\\\"],\\\\n      \\\\\\\"industry_seeds\\\\\\\": [\\\\\\\"saas\\\\\\\", \\\\\\\"consumer_brand\\\\\\\", \\\\\\\"ai_tools\\\\\\\", \\\\\\\"creator_econ\\\\\\\"],\\\\n      \\\\\\\"looking_for\\\\\\\": [\\\\\\\"日本市場entry\\\\\\\", \\\\\\\"現地co_seller\\\\\\\", \\\\\\\"PoC customer\\\\\\\"],\\\\n      \\\\\\\"can_offer\\\\\\\": [\\\\\\\"プロダクト / 技術\\\\\\\", \\\\\\\"華語圏スケール\\\\\\\"],\\\\n      \\\\\\\"tone\\\\\\\": \\\\\\\"速さ重視、結果ドリブン\\\\\\\",\\\\n      \\\\\\\"follow_up_channel\\\\\\\": \\\\\\\"wechat_then_email\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"id\\\\\\\": \\\\\\\"investor_or_vc\\\\\\\",\\\\n      \\\\\\\"label\\\\\\\": \\\\\\\"投資家 / VC / angel\\\\\\\",\\\\n      \\\\\\\"weight_pct\\\\\\\": \\\\\\\"8-12\\\\\\\",\\\\n      \\\\\\\"language\\\\\\\": [\\\\\\\"ja\\\\\\\", \\\\\\\"en\\\\\\\"],\\\\n      \\\\\\\"industry_seeds\\\\\\\": [\\\\\\\"vc\\\\\\\", \\\\\\\"family_office\\\\\\\", \\\\\\\"growth_fund\\\\\\\"],\\\\n      \\\\\\\"looking_for\\\\\\\": [\\\\\\\"deal flow\\\\\\\", \\\\\\\"cross_border thesis\\\\\\\", \\\\\\\"co-invest\\\\\\\"],\\\\n      \\\\\\\"can_offer\\\\\\\": [\\\\\\\"資金\\\\\\\", \\\\\\\"introductions\\\\\\\", \\\\\\\"portfolio playbooks\\\\\\\"],\\\\n      \\\\\\\"tone\\\\\\\": \\\\\\\"短時間判断、ROI 言語\\\\\\\",\\\\n      \\\\\\\"follow_up_channel\\\\\\\": \\\\\\\"email\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"id\\\\\\\": \\\\\\\"community_connector\\\\\\\",\\\\n      \\\\\\\"label\\\\\\\": \\\\\\\"コミュニティ運営者 / 記者 / KOL\\\\\\\",\\\\n      \\\\\\\"weight_pct\\\\\\\": \\\\\\\"5-8\\\\\\\",\\\\n      \\\\\\\"language\\\\\\\": [\\\\\\\"ja\\\\\\\", \\\\\\\"zh\\\\\\\", \\\\\\\"mixed\\\\\\\"],\\\\n      \\\\\\\"industry_seeds\\\\\\\": [\\\\\\\"media\\\\\\\", \\\\\\\"community_org\\\\\\\", \\\\\\\"association\\\\\\\"],\\\\n      \\\\\\\"looking_for\\\\\\\": [\\\\\\\"登壇者\\\\\\\", \\\\\\\"取材ネタ\\\\\\\", \\\\\\\"共催パートナー\\\\\\\"],\\\\n      \\\\\\\"can_offer\\\\\\\": [\\\\\\\"露出\\\\\\\", \\\\\\\"動員力\\\\\\\", \\\\\\\"信用付与\\\\\\\"],\\\\n      \\\\\\\"tone\\\\\\\": \\\\\\\"関係構築重視、物語志向\\\\\\\",\\\\n      \\\\\\\"follow_up_channel\\\\\\\": \\\\\\\"dm_then_email\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"id\\\\\\\": \\\\\\\"negative_negative\\\\\\\",\\\\n      \\\\\\\"label\\\\\\\": \\\\\\\"意図的に弱い一致 / ノイズ学生・求職者\\\\\\\",\\\\n      \\\\\\\"weight_pct\\\\\\\": \\\\\\\"5-10\\\\\\\",\\\\n      \\\\\\\"language\\\\\\\": [\\\\\\\"ja\\\\\\\", \\\\\\\"zh\\\\\\\"],\\\\n      \\\\\\\"industry_seeds\\\\\\\": [\\\\\\\"student\\\\\\\", \\\\\\\"jobseeker\\\\\\\", \\\\\\\"hobbyist\\\\\\\"],\\\\n      \\\\\\\"looking_for\\\\\\\": [\\\\\\\"趣味の友達\\\\\\\", \\\\\\\"就活情報\\\\\\\"],\\\\n      \\\\\\\"can_offer\\\\\\\": [],\\\\n      \\\\\\\"tone\\\\\\\": \\\\\\\"テスト用のbad_match負荷生成\\\\\\\",\\\\n      \\\\\\\"follow_up_channel\\\\\\\": \\\\\\\"none\\\\\\\",\\\\n      \\\\\\\"note\\\\\\\": \\\\\\\"These generate golden-match 負例 (bad_match) and dirty cases; not real conversion paths.\\\\\\\"\\\\n    }\\\\n  ],\\\\n  \\\\\\\"scenario_emphasis\\\\\\\": [\\\\n    {\\\\n      \\\\\\\"event_archetype\\\\\\\": \\\\\\\"inbound_food_marketing\\\\\\\",\\\\n      \\\\\\\"weight\\\\\\\": \\\\\\\"high\\\\\\\",\\\\n      \\\\\\\"purpose\\\\\\\": \\\\\\\"日本飲食店 × 華語マーケティング橋渡し — golden_match の primary fixture\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"event_archetype\\\\\\\": \\\\\\\"ai_dx_poc\\\\\\\",\\\\n      \\\\\\\"weight\\\\\\\": \\\\\\\"high\\\\\\\",\\\\n      \\\\\\\"purpose\\\\\\\": \\\\\\\"中小製造業向け AI / DX 提案 — buyer_seller 推薦検証\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"event_archetype\\\\\\\": \\\\\\\"investor_mixer\\\\\\\",\\\\n      \\\\\\\"weight\\\\\\\": \\\\\\\"medium\\\\\\\",\\\\n      \\\\\\\"purpose\\\\\\\": \\\\\\\"investor_founder / market_entry 推薦検証\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"event_archetype\\\\\\\": \\\\\\\"cn_founder_dinner\\\\\\\",\\\\n      \\\\\\\"weight\\\\\\\": \\\\\\\"medium\\\\\\\",\\\\n      \\\\\\\"purpose\\\\\\\": \\\\\\\"大中華区 founder の日本市場 entry 検証\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"event_archetype\\\\\\\": \\\\\\\"community_connector_salon\\\\\\\",\\\\n      \\\\\\\"weight\\\\\\\": \\\\\\\"medium\\\\\\\",\\\\n      \\\\\\\"purpose\\\\\\\": \\\\\\\"コミュニティ・メディア role の relationship_style 差を検証\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"event_archetype\\\\\\\": \\\\\\\"noisy_career_fair\\\\\\\",\\\\n      \\\\\\\"weight\\\\\\\": \\\\\\\"low\\\\\\\",\\\\n      \\\\\\\"purpose\\\\\\\": \\\\\\\"bad_match / negative_case を大量に供給する dirty-case イベント\\\\\\\"\\\\n    }\\\\n  ],\\\\n  \\\\\\\"dirty_case_policy\\\\\\\": [\\\\n    \\\\\\\"Encode dirty cases explicitly into the schema, do not hide them — every user/event/company record carries `data_quality_flags: string[]` (e.g., `industry_too_broad`, `looking_for_boilerplate`, `language_conflict`, `missing_company`).\\\\\\\",\\\\n    \\\\\\\"Boilerplate 拒否ルール: 'I want to meet interesting people' / '我对 AI 感兴趣' / '我想拓展人脉' のような generic ステートメントは `looking_for_at_event` ではなく `dirty_lookup_phrases` に隔離し、推薦説明文で再利用させない.\\\\\\\",\\\\n    \\\\\\\"矛盾はサイレントに average 化しない — 言語設定が looking_for と矛盾する場合 (例: looking_for = 中国語対応 but preferred_language = [ja] only) は `metadata.tension_notes` に明示し、recommended_explanation には反映する.\\\\\\\",\\\\n    \\\\\\\"EventParticipant role と status に整合性チェック — organizer が no_show、vip が cancelled などがあり得るが、それは `dirty_status_combos` として故意に少量混入させ、レコメンダがこれらをどう扱うかテスト可能にする.\\\\\\\",\\\\n    \\\\\\\"Golden-match の `negative_case: true` は bad_match 単体ではなく「高スコアに見えるが実は弱い」 (e.g., 表面上は buyer_seller だが業種詳細不一致) を含める.\\\\\\\",\\\\n    \\\\\\\"Dirty cases は全体の約5–8% にキャップし、推薦ロジックの通常動作を壊さない範囲で混入.\\\\\\\",\\\\n    \\\\\\\"汚染記録はレポートに必ずリストアップし、silent skip を禁ずる — 生成完了時に dirty_records.json を必ず出力する.\\\\\\\"\\\\n  ],\\\\n  \\\\\\\"conservative_ai_policy\\\\\\\": [\\\\n    \\\\\\\"全ての AI 出力は confirmed_facts と inferred_traits に分離し、inferred 側には confidence (0.0–1.0) と source_refs を必須付与.\\\\\\\",\\\\n    \\\\\\\"confidence < 0.6 の推測は recommendation_explanation の主根拠にしない — 補助的言及にとどめ、evidence 配列には載せない.\\\\\\\",\\\\n    \\\\\\\"存在しない人物・企業・数字 (例: '3年連続No.1'、実在しない VC 名) を捏造しない — 必要なら `unverified_claim` フラグで隔離し、reason 文中では『〜と申告』等の attribution 表現を使う.\\\\\\\",\\\\n    \\\\\\\"言語切替は根拠ベース: ユーザーの confirmed_facts.preferred_language が ja のみなら recommendation_explanation.ja を主、zh を副、en は不要なら省略。逆に混合言話は bilingual 必須.\\\\\\\",\\\\n    \\\\\\\"Match type 選択は evidence 件数 ≥ 2 を満たさない限り weak_match に降格し、bad_match は golden が陰性指定した組み合わせのみで使用.\\\\\\\",\\\\n    \\\\\\\"Culturally sensitive な断定 (出身・宗教・政治) は confirmed_facts にしか載せず、inferred に持ち込まない.\\\\\\\",\\\\n    \\\\\\\"follow_up_suggestion は具体的かつ低リスク — 『24時間以内に送る』『30分のオンライン打診を提案』のようにアクション可能な粒度で、勝手に DM 送信 / 連絡先共有を前提にしない.\\\\\\\",\\\\n    \\\\\\\"Generated text は no-ai-tone に準拠 — 過剰な絵文字、リスト爆撃、AI の自己言及を避け、人間的な長さの段落を基調とする.\\\\\\\"\\\\n  ],\\\\n  \\\\\\\"follow_up_tone\\\\\\\": {\\\\n    \\\\\\\"default_persona\\\\\\\": \\\\\\\"jp_sme_owner\\\\\\\",\\\\n    \\\\\\\"principles\\\\\\\": [\\\\n      \\\\\\\"日文相手の first follow-up は必ず日本語で書き、過剰に Casual にならない (です/ます 調).\\\\\\\",\\\\n      \\\\\\\"华人 operator 相手の first follow-up は中文で、WeChat / 微信の距離を許容する柔らかい口調.\\\\\\\",\\\\n      \\\\\\\"Investor には1〜2文の Punch + 提案アクション (オンライン15分打診) に圧縮.\\\\\\\",\\\\n      \\\\\\\"全ての follow-up は『前イベントの具体的トピック』を最低1つ参照し、定型文化を回避.\\\\\\\",\\\\n      \\\\\\\"『すごい / amazing / 素晴らしい』等の過度評価を避け、相手の具体発言を引用する形にする.\\\\\\\",\\\\n      \\\\\\\"Call-to-action は1つに絞る (再会 / 資料送付 / 15分面談のどれか).\\\\\\\",\\\\n      \\\\\\\"不快リスクが高い話題 (宗教、政治、個人批判) には踏み込まない.\\\\\\\",\\\\n      \\\\\\\"Orbit 製品名は mention しない — ユーザー間の自然な関係進行を演出.\\\\\\\"\\\\n    ],\\\\n    \\\\\\\"templates_by_match_type\\\\\\\": {\\\\n      \\\\\\\"buyer_seller\\\\\\\": \\\\\\\"導入示唆型 — 相手の課題引用 + 小規模 PoC 提案 + 日程打診\\\\\\\",\\\\n      \\\\\\\"investor_founder\\\\\\\": \\\\\\\"Short pitch 型 — ハイライト1つ + 30秒の video / 1枚資料提案\\\\\\\",\\\\n      \\\\\\\"market_entry\\\\\\\": \\\\\\\"Educate 逆提案型 — 相手の市場知識を引用 + 自社側ヒアリング依頼\\\\\\\",\\\\n      \\\\\\\"channel_partner\\\\\\\": \\\\\\\"Co-build 型 — 共催イベント or 共同コンテンツ提案\\\\\\\",\\\\n      \\\\\\\"knowledge_exchange\\\\\\\": \\\\\\\"Curiosity 型 — 参考になりそうな一次情報を添付\\\\\\\",\\\\n      \\\\\\\"community_connector\\\\\\\": \\\\\\\"Relationship seeding 型 — 互いの network を持ち寄る打診\\\\\\\",\\\\n      \\\\\\\"follow_up_priority\\\\\\\": \\\\\\\"Reliability 型 — 24時間以内返信、要点1つに絞る\\\\\\\",\\\\n      \\\\\\\"weak_match\\\\\\\": \\\\\\\"短く礼儀のみ、断定的 next action を提示しない\\\\\\\",\\\\n      \\\\\\\"bad_match\\\\\\\": \\\\\\\"出力しない (negative_case として golden_match にのみ記録)\\\\\\\"\\\\n    },\\\\n    \\\\\\\"language_routing\\\\\\\": {\\\\n      \\\\\\\"ja_only_user\\\\\\\": \\\\\\\"ja primary, zh absent or minor\\\\\\\",\\\\n      \\\\\\\"zh_primary_user\\\\\\\": \\\\\\\"zh primary, en minor\\\\\\\",\\\\n      \\\\\\\"mixed_user\\\\\\\": \\\\\\\"bilingual short para, primary in user.preferred_language[0]\\\\\\\"\\\\n    }\\\\n  }\\\\n}\\\\n```\\\"\\n}\\n\"\n}\n"
